class LoggingObserver extends NavigatorObserver {
  @override
  void didPush(Route route, Route? previousRoute) {
    AppLogger.userInteraction(
      action: 'NAVIGATE_PUSH',
      screen: route.settings.name ?? route.runtimeType.toString(),
      data: {
        'previous': previousRoute?.settings.name ?? previousRoute?.runtimeType.toString(),
      },
    );
    super.didPush(route, previousRoute);
  }

  @override
  void didPop(Route route, Route? previousRoute) {
    AppLogger.userInteraction(
      action: 'NAVIGATE_POP',
      screen: route.settings.name ?? route.runtimeType.toString(),
      data: {
        'previous': previousRoute?.settings.name ?? previousRoute?.runtimeType.toString(),
      },
    );
    super.didPop(route, previousRoute);
  }
}

